def check_string_type(s):
    if (s.startswith("http://") and len(s) > 7) or (s.startswith("https://") and len(s) > 8):
        return "URL"

    if s.count('@') == 1:
        local_part, domain_part = s.split('@')
        if local_part and domain_part and '.' in domain_part and not domain_part.startswith('.') and not domain_part.endswith('.'):
             return "Email"

    if s.isidentifier():
        return "Identifier"

    return "Invalid"

input_string = input()
print(check_string_type(input_string))
